package com.restaurantcraft.blockentity; import com.restaurantcraft.registry.ModBlockEntities; import net.minecraft.core.BlockPos; import net.minecraft.nbt.CompoundTag; import net.minecraft.world.level.block.entity.BlockEntity; import net.minecraft.world.level.block.state.BlockState; public class RestaurantChairBlockEntity extends BlockEntity { private boolean occupied; public RestaurantChairBlockEntity(BlockPos p, BlockState s){super(ModBlockEntities.RESTAURANT_CHAIR.get(),p,s);} public boolean isOccupied(){return occupied;} public void setOccupied(boolean v){occupied=v; setChanged();} protected void saveAdditional(CompoundTag t){super.saveAdditional(t);t.putBoolean("Occupied",occupied);} public void load(CompoundTag t){super.load(t);occupied=t.getBoolean("Occupied");} }
